  1→import { getFloorElevation } from '@/domain/floorModels';
  2→import { getSlabBottomLevel } from '@/elevations/slab';
  3→import { getBeamRenderData } from '@/geometry/beamGeometry';
  4→import { computeLandingElevation } from '@/geometry/landingGeometry';
  5→import { isValidSlabBoundary } from '@/geometry/slabGeometry';
  6→import { getStairRenderData } from '@/geometry/stairGeometry';
  7→import { wallDirection, wallLength, wallOutline } from '@/geometry/wallGeometry';
  8→import { buildWallPreviewContexts, buildWallSolidSegments } from './wallPreviewContext';
  9→
 10→const DOOR_INSERT_THICKNESS_MIN = 35;
 11→const DOOR_INSERT_THICKNESS_MAX = 70;
 12→const WINDOW_INSERT_THICKNESS_MIN = 45;
 13→const WINDOW_INSERT_THICKNESS_MAX = 90;
 14→
 15→function createBoundsFromPoints(points, baseElevation, topElevation) {
 16→  if (!points?.length) {
 17→    return {
 18→      minX: 0,
 19→      maxX: 0,
 20→      minY: 0,
 21→      maxY: 0,
 22→      minElevation: baseElevation,
 23→      maxElevation: topElevation,
 24→    };
 25→  }
 26→
 27→  return {
 28→    minX: Math.min(...points.map((point) => point.x)),
 29→    maxX: Math.max(...points.map((point) => point.x)),
 30→    minY: Math.min(...points.map((point) => point.y)),
 31→    maxY: Math.max(...points.map((point) => point.y)),
 32→    minElevation: baseElevation,
 33→    maxElevation: topElevation,
 34→  };
 35→}
 36→
 37→function createPrismDescriptor(id, kind, outline, baseElevation, height, metadata = {}) {
 38→  const topElevation = baseElevation + height;
 39→  return {
 40→    id,
 41→    kind,
 42→    geometry: 'prism',
 43→    outline: outline.map((point) => ({ x: point.x, y: point.y })),
 44→    baseElevation,
 45→    height,
 46→    materialKey: metadata.materialKey || kind,
 47→    metadata,
 48→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 49→  };
 50→}
 51→
 52→function createLinearBoxDescriptor(id, kind, startPoint, endPoint, width, baseElevation, height, metadata = {}) {
 53→  const outline = wallOutline({
 54→    start: { x: startPoint.x, y: startPoint.y },
 55→    end: { x: endPoint.x, y: endPoint.y },
 56→    thickness: width,
 57→  });
 58→  const direction = wallDirection({
 59→    start: { x: startPoint.x, y: startPoint.y },
 60→    end: { x: endPoint.x, y: endPoint.y },
 61→  });
 62→  const topElevation = baseElevation + height;
 63→
 64→  return {
 65→    id,
 66→    kind,
 67→    geometry: 'box',
 68→    center: {
 69→      x: (startPoint.x + endPoint.x) / 2,
 70→      y: (startPoint.y + endPoint.y) / 2,
 71→    },
 72→    size: {
 73→      x: wallLength({ start: startPoint, end: endPoint }),
 74→      y: height,
 75→      z: width,
 76→    },
 77→    rotation: Math.atan2(direction.y, direction.x),
 78→    baseElevation,
 79→    materialKey: metadata.materialKey || kind,
 80→    metadata,
 81→    bounds: createBoundsFromPoints(outline, baseElevation, topElevation),
 82→  };
 83→}
 84→
 85→function createBoxDescriptor(id, kind, center, size, baseElevation, rotation = 0, metadata = {}) {
 86→  const halfX = size.x / 2;
 87→  const halfZ = size.z / 2;
 88→  const cos = Math.cos(rotation);
 89→  const sin = Math.sin(rotation);
 90→  const corners = [
 91→    { x: -halfX, y: -halfZ },
 92→    { x: halfX, y: -halfZ },
 93→    { x: halfX, y: halfZ },
 94→    { x: -halfX, y: halfZ },
 95→  ].map((point) => ({
 96→    x: center.x + (point.x * cos - point.y * sin),
 97→    y: center.y + (point.x * sin + point.y * cos),
 98→  }));
 99→
100→  return {
101→    id,
102→    kind,
103→    geometry: 'box',
104→    center: { x: center.x, y: center.y },
105→    size,
106→    rotation,
107→    baseElevation,
108→    materialKey: metadata.materialKey || kind,
109→    metadata,
110→    bounds: createBoundsFromPoints(corners, baseElevation, baseElevation + size.y),
111→  };
112→}
113→
114→function resolveLandingElevation(landing, stairs, floorLevel) {
115→  if (landing.elevation) return landing.elevation;
116→  return computeLandingElevation(landing, stairs, floorLevel) - floorLevel;
117→}
118→
119→function createStairDescriptor(stair, floorLevel, floorId, landings, landingElevationMap) {
120→  const renderData = getStairRenderData(stair);
121→  if (!renderData?.outline?.length) return null;
122→
123→  let baseElevation = floorLevel;
124→  if (stair.startLandingAttachment) {
125→    const elev = landingElevationMap?.get(stair.startLandingAttachment.landingId);
126→    if (elev != null) {
127→      baseElevation = floorLevel + elev;
128→    }
129→  }
130→
131→  return {
132→    id: stair.id,
133→    kind: 'stair',
134→    geometry: 'stair',
135→    startPoint: { ...stair.startPoint },
136→    width: stair.width,
137→    numberOfRisers: stair.numberOfRisers,
138→    riserHeight: stair.riserHeight,
139→    treadDepth: stair.treadDepth,
140→    angle: renderData.angle,
141→    baseElevation,
142→    materialKey: 'stair',
143→    metadata: {
144→      sourceId: stair.id,
145→      floorId,
146→    },
147→    bounds: createBoundsFromPoints(
148→      renderData.outline,
149→      baseElevation,
150→      baseElevation + renderData.totalRise
151→    ),
152→  };
153→}
154→
155→function buildWallObjects(wallContexts) {
156→  return wallContexts.flatMap((context) => (
157→    buildWallSolidSegments(context).map((segment) => createLinearBoxDescriptor(
158→      segment.id,
159→      'wall',
160→      segment.startPoint,
161→      segment.endPoint,
162→      segment.thickness,
163→      segment.baseElevation,
164→      segment.topElevation - segment.baseElevation,
165→      {
166→        sourceId: segment.wallId,
167→        floorId: segment.floorId,
168→        wallId: segment.wallId,
169→      }
170→    ))
171→  ));
172→}
173→
174→function buildSlabObjects(floor) {
175→  return (floor.slabs || [])
176→    .filter(slab => isValidSlabBoundary(slab.boundaryPoints))
177→    .map(slab => createPrismDescriptor(
178→      slab.id,
179→      'slab',
180→      slab.boundaryPoints,
181→      getSlabBottomLevel(slab),
182→      slab.thickness ?? 0,
183→      {
184→        sourceId: slab.id,
185→        floorId: floor.id,
186→      }
187→    ));
188→}
189→
190→function buildColumnObjects(floor, floorLevel) {
191→  return (floor.columns || []).map((column) => createBoxDescriptor(
192→    column.id,
193→    'column',
194→    { x: column.x, y: column.y },
195→    {
196→      x: column.width,
197→      y: column.height,
198→      z: column.depth,
199→    },
200→    floorLevel,
201→    (column.rotation || 0) * Math.PI / 180,
202→    {
203→      sourceId: column.id,
204→      floorId: floor.id,
205→    }
206→  ));
207→}
208→
209→function buildBeamObjects(floor) {
210→  return (floor.beams || [])
211→    .map((beam) => {
212→      const renderData = getBeamRenderData(beam, floor.columns || []);
213→      if (!renderData) return null;
214→
215→      return createLinearBoxDescriptor(
216→        beam.id,
217→        'beam',
218→        renderData.start,
219→        renderData.end,
220→        beam.width,
221→        beam.floorLevel - beam.depth,
222→        beam.depth,
223→        {
224→          sourceId: beam.id,
225→          floorId: floor.id,
226→        }
227→      );
228→    })
229→    .filter(Boolean);
230→}
231→
232→function getInsertThickness(kind, wallThickness) {
233→  if (kind === 'door') {
234→    return Math.max(
235→      DOOR_INSERT_THICKNESS_MIN,
236→      Math.min(wallThickness * 0.22, DOOR_INSERT_THICKNESS_MAX)
237→    );
238→  }
239→
240→  return Math.max(
241→    WINDOW_INSERT_THICKNESS_MIN,
242→    Math.min(wallThickness * 0.32, WINDOW_INSERT_THICKNESS_MAX)
243→  );
244→}
245→
246→function createOpeningInsertDescriptor(opening) {
247→  return createBoxDescriptor(
248→    opening.id,
249→    opening.kind,
250→    opening.centerPoint,
251→    {
252→      x: opening.visibleWidth,
253→      y: opening.visibleHeight,
254→      z: getInsertThickness(opening.kind, opening.wallThickness),
255→    },
256→    opening.visibleBaseElevation,
257→    opening.angle,
258→    {
259→      sourceId: opening.sourceId,
260→      floorId: opening.metadata.floorId,
261→      wallId: opening.wallId,
262→      openingKind: opening.kind,
263→    }
264→  );
265→}
266→
267→function buildDoorObjects(wallContexts) {
268→  return wallContexts
269→    .flatMap((context) => context.openings)
270→    .filter((opening) => opening.kind === 'door')
271→    .map((opening) => createOpeningInsertDescriptor(opening));
272→}
273→
274→function buildWindowObjects(wallContexts) {
275→  return wallContexts
276→    .flatMap((context) => context.openings)
277→    .filter((opening) => opening.kind === 'window')
278→    .map((opening) => {
279→      const desc = createOpeningInsertDescriptor(opening);
280→      desc.geometry = 'window';
281→      desc.windowType = opening.type || 'standard';
282→      desc.openDirection = opening.openDirection || 'left';
283→      return desc;
284→    });
285→}
286→
287→function buildStairObjects(floor, floorLevel, landings, landingElevationMap) {
288→  return (floor.stairs || [])
289→    .map((stair) => createStairDescriptor(stair, floorLevel, floor.id, landings, landingElevationMap))
290→    .filter(Boolean);
291→}
292→
293→function buildLandingObjects(floor, floorLevel, landingElevationMap) {
294→  return (floor.landings || []).map((landing) => createBoxDescriptor(
295→    landing.id,
296→    'landing',
297→    { x: landing.position.x, y: landing.position.y },
298→    {
299→      x: landing.width,
300→      y: landing.thickness ?? 200,
301→      z: landing.depth,
302→    },
303→    floorLevel + (landingElevationMap.get(landing.id) || 0),
304→    (landing.rotation || 0) * Math.PI / 180,
305→    {
306→      sourceId: landing.id,
307→      floorId: floor.id,
308→    }
309→  ));
310→}
311→
312→export function buildFloorPreviewObjects(floor) {
313→  const floorLevel = getFloorElevation(floor);
314→  const landings = floor.landings || [];
315→  const stairs = floor.stairs || [];
316→
317→  const landingElevationMap = new Map(
318→    landings.map(l => [l.id, resolveLandingElevation(l, stairs, floorLevel)])
319→  );
320→
321→  const wallContexts = buildWallPreviewContexts(floor, floorLevel);
322→
323→  return [
324→    ...buildSlabObjects(floor),
325→    ...buildWallObjects(wallContexts),
326→    ...buildColumnObjects(floor, floorLevel),
327→    ...buildBeamObjects(floor),
328→    ...buildStairObjects(floor, floorLevel, landings, landingElevationMap),
329→    ...buildLandingObjects(floor, floorLevel, landingElevationMap),
330→    ...buildDoorObjects(wallContexts),
331→    ...buildWindowObjects(wallContexts),
332→  ];
333→}
