  1→import * as THREE from 'three';
  2→import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls.js';
  3→import { createMaterialPalette, disposeMaterialPalette } from './materials';
  4→import { disposeScene } from './disposeScene';
  5→
  6→const DEFAULT_PRESET_NAME = 'plan_aligned';
  7→
  8→const PRESETS = {
  9→  // Match the SVG blueprint's top/bottom and left/right reading in the preview.
 10→  plan_aligned: new THREE.Vector3(-1.1, 0.92, 1.05),
 11→  default: new THREE.Vector3(-1.1, 0.92, 1.05),
 12→  iso_northeast: new THREE.Vector3(1, 0.88, 1),
 13→  iso_northwest: new THREE.Vector3(-1, 0.88, 1),
 14→  iso_southeast: new THREE.Vector3(1, 0.88, -1),
 15→  iso_southwest: new THREE.Vector3(-1, 0.88, -1),
 16→};
 17→
 18→function descriptorBoundsToWorldBox(bounds) {
 19→  return new THREE.Box3(
 20→    new THREE.Vector3(bounds.minX, bounds.minElevation, bounds.minY),
 21→    new THREE.Vector3(bounds.maxX, bounds.maxElevation, bounds.maxY)
 22→  );
 23→}
 24→
 25→function createGrid(bounds, groundLevel) {
 26→  const size = Math.max(
 27→    bounds.maxX - bounds.minX,
 28→    bounds.maxY - bounds.minY,
 29→    4000
 30→  );
 31→  const normalizedSize = Math.ceil(size / 1000) * 1000;
 32→  const divisions = Math.max(8, Math.round(normalizedSize / 500));
 33→  const grid = new THREE.GridHelper(normalizedSize, divisions, 0x8fa1b4, 0xc7d1db);
 34→  grid.position.y = groundLevel;
 35→  grid.material.transparent = true;
 36→  grid.material.opacity = 0.45;
 37→  return grid;
 38→}
 39→
 40→function fitCameraToBox(camera, controls, box, presetName) {
 41→  const preset = PRESETS[presetName] || PRESETS[DEFAULT_PRESET_NAME];
 42→  const direction = preset.clone().normalize();
 43→  const size = box.getSize(new THREE.Vector3());
 44→  const center = box.getCenter(new THREE.Vector3());
 45→  const radius = Math.max(size.length() / 2, 1200);
 46→  const halfFovY = THREE.MathUtils.degToRad(camera.fov / 2);
 47→  const halfFovX = Math.atan(Math.tan(halfFovY) * camera.aspect);
 48→  const distanceByHeight = Math.max(size.y, size.z) / (2 * Math.tan(halfFovY));
 49→  const distanceByWidth = Math.max(size.x, size.z) / (2 * Math.tan(halfFovX));
 50→  const distance = Math.max(distanceByHeight, distanceByWidth, radius * 1.4) * 1.15;
 51→
 52→  controls.target.copy(center);
 53→  camera.position.copy(center.clone().add(direction.multiplyScalar(distance)));
 54→  camera.near = Math.max(10, distance / 200);
 55→  camera.far = distance * 10;
 56→  camera.updateProjectionMatrix();
 57→  controls.update();
 58→}
 59→
 60→export function createPreviewViewport(container) {
 61→  const materialPalette = createMaterialPalette();
 62→  const scene = new THREE.Scene();
 63→  scene.background = null;
 64→
 65→  const camera = new THREE.PerspectiveCamera(42, 1, 10, 100000);
 66→  const renderer = new THREE.WebGLRenderer({
 67→    antialias: true,
 68→    alpha: true,
 69→    powerPreference: 'high-performance',
 70→  });
 71→  renderer.outputColorSpace = THREE.SRGBColorSpace;
 72→  renderer.setPixelRatio(Math.min(window.devicePixelRatio || 1, 2));
 73→  renderer.setSize(container.clientWidth || 1, container.clientHeight || 1, false);
 74→  renderer.domElement.style.width = '100%';
 75→  renderer.domElement.style.height = '100%';
 76→  renderer.domElement.style.display = 'block';
 77→  container.appendChild(renderer.domElement);
 78→
 79→  const controls = new OrbitControls(camera, renderer.domElement);
 80→  controls.enableDamping = true;
 81→  controls.dampingFactor = 0.08;
 82→  controls.screenSpacePanning = true;
 83→  controls.minDistance = 400;
 84→  controls.maxDistance = 150000;
 85→  controls.maxPolarAngle = Math.PI * 0.495;
 86→
 87→  scene.add(new THREE.AmbientLight(0xffffff, 0.72));
 88→  scene.add(new THREE.HemisphereLight(0xdde7f4, 0xe6ded0, 0.7));
 89→  const keyLight = new THREE.DirectionalLight(0xffffff, 1.05);
 90→  keyLight.position.set(3500, 5000, 2000);
 91→  scene.add(keyLight);
 92→
 93→  let animationFrame = 0;
 94→  let worldRoot = null;
 95→  let gridHelper = null;
 96→  let currentBounds = null;
 97→  let currentPreset = DEFAULT_PRESET_NAME;
 98→
 99→  const renderFrame = () => {
100→    controls.update();
101→    renderer.render(scene, camera);
102→    animationFrame = window.requestAnimationFrame(renderFrame);
103→  };
104→
105→  const resize = () => {
106→    const width = container.clientWidth || 1;
107→    const height = container.clientHeight || 1;
108→    camera.aspect = width / height;
109→    camera.updateProjectionMatrix();
110→    renderer.setSize(width, height, false);
111→  };
112→
113→  animationFrame = window.requestAnimationFrame(renderFrame);
114→
115→  return {
116→    setWorld(nextRoot, bounds, groundLevel = 0) {
117→      const hadWorld = !!worldRoot;
118→      if (worldRoot) {
119→        scene.remove(worldRoot);
120→        disposeScene(worldRoot);
121→      }
122→
123→      if (gridHelper) {
124→        scene.remove(gridHelper);
125→        gridHelper.geometry?.dispose?.();
126→        gridHelper.material?.dispose?.();
127→      }
128→
129→      worldRoot = nextRoot;
130→      currentBounds = descriptorBoundsToWorldBox(bounds);
131→      gridHelper = createGrid(bounds, groundLevel);
132→      scene.add(gridHelper);
133→      scene.add(worldRoot);
134→      if (!hadWorld) fitCameraToBox(camera, controls, currentBounds, currentPreset);
135→    },
136→    resetView() {
137→      if (!currentBounds) return;
138→      fitCameraToBox(camera, controls, currentBounds, currentPreset);
139→    },
140→    fit() {
141→      if (!currentBounds) return;
142→      fitCameraToBox(camera, controls, currentBounds, currentPreset);
143→    },
144→    setProjectionPreset(presetName = DEFAULT_PRESET_NAME) {
145→      currentPreset = presetName in PRESETS ? presetName : DEFAULT_PRESET_NAME;
146→      if (!currentBounds) return;
147→      fitCameraToBox(camera, controls, currentBounds, currentPreset);
148→    },
149→    resize,
150→    dispose() {
151→      window.cancelAnimationFrame(animationFrame);
152→      controls.dispose();
153→
154→      if (worldRoot) {
155→        scene.remove(worldRoot);
156→        disposeScene(worldRoot);
157→      }
158→
159→      if (gridHelper) {
160→        scene.remove(gridHelper);
161→        gridHelper.geometry?.dispose?.();
162→        gridHelper.material?.dispose?.();
163→      }
164→
165→      disposeMaterialPalette(materialPalette);
166→      renderer.dispose();
167→      renderer.domElement.remove();
168→    },
169→    materialPalette,
170→  };
171→}
