 77→export function buildWallPreviewContext(floor, wall, floorLevel) {
 78→  const wallRenderData = getWallRenderData(wall, floor.columns || []);
 79→  const sourceWall = wallRenderData.wall;
 80→  const renderWall = wallRenderData.renderWall;
 81→  const trimStartAlong = projectPointOnWall(sourceWall, renderWall.start);
 82→  const trimEndAlong = projectPointOnWall(sourceWall, renderWall.end);
 83→  const context = {
 84→    floorId: floor.id,
 85→    wall,
 86→    sourceWall,
 87→    renderWall,
 88→    wallRenderData,
 89→    trimStartAlong,
 90→    trimEndAlong,
 91→    renderLength: wallLength(renderWall),
 92→    wallBase: floorLevel,
 93→    wallTop: floorLevel + (wall.height ?? 0),
 94→  };
 95→
 96→  const openings = [
 97→    ...(floor.doors || []).filter((item) => item.wallId === wall.id).map((door) => (
 98→      buildOpeningDescriptor('door', door, context)
 99→    )),
100→    ...(floor.windows || []).filter((item) => item.wallId === wall.id).map((windowItem) => (
101→      buildOpeningDescriptor('window', windowItem, context)
102→    )),
103→  ]
104→    .filter(Boolean)
105→    .sort((left, right) => left.startAlong - right.startAlong);
106→
107→  return {
108→    ...context,
109→    openings,
110→  };
111→}
